mapper.select:
SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT p.PAGE_ID AS pageId, p.PAGE_NAME AS pageName, p.CREATE_USER_NAME AS createUserName, CASE WHEN lh.FILE_ID IS NOT NULL THEN 'http://' || si.INSTANCE_IP || ':' || TO_CHAR(si.INSTANCE_PORT) || '/cms/deployed/' || p.PAGE_ID || '.html' END AS deployedUrl, TO_CHAR(p.BEGINNING_DATE, 'YYYY-MM-DD') AS beginningDate, TO_CHAR(p.EXPIRED_DATE, 'YYYY-MM-DD') AS expiredDate, p.IS_PUBLIC AS isPublic,
CASE WHEN p.EXPIRED_DATE IS NOT NULL AND p.EXPIRED_DATE < SYSDATE AND p.IS_PUBLIC = 'Y' THEN 'Y' ELSE 'N' END AS isExpired FROM SPW_CMS_PAGE p LEFT JOIN ( SELECT REGEXP_REPLACE(FILE_ID, '_v\d+\.html$', '') AS PAGE_ID, FILE_ID, INSTANCE_ID, ROW_NUMBER() OVER ( PARTITION BY REGEXP_REPLACE(FILE_ID, '_v\d+\.html$', '') ORDER BY LAST_MODIFIED_DTIME DESC ) AS RN FROM FWK_CMS_FILE_SEND_HIS
WHERE FILE_ID LIKE '%_v%.html' AND FILE_ID NOT LIKE '%_expired.html' ) lh ON lh.PAGE_ID = p.PAGE_ID AND lh.RN = 1 LEFT JOIN FWK_CMS_SERVER_INSTANCE si ON lh.INSTANCE_ID = si.INSTANCE_ID
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}

mapper.update:
UPDATE SPW_CMS_PAGE
SET
    IS_PUBLIC        = 'N',
    FILE_PATH_BACK   = FILE_PATH,
    LAST_MODIFIER_ID = #{userId}
WHERE PAGE_ID = #{pageId}
